// --- UTILS ---------------------------------------------------
const fmt = n => new Intl.NumberFormat("en-US",{style:"currency",currency:"USD"}).format(n);
const fmtN = n => new Intl.NumberFormat("en-US").format(n);
const pct = n => `${n.toFixed(1)}%`;
const uid = () => Math.random().toString(36).substr(2,9);
const exportCSV = (headers, rows, filename) => {
  const csv = [headers.join(','), ...rows.map(r => r.map(c => '"'+(String(c).replace(/"/g,'""'))+'"').join(','))].join('\n');
  const blob = new Blob([csv], {type: 'text/csv'});
  const url = URL.createObjectURL(blob);
  const a = document.createElement('a'); a.href = url; a.download = filename; a.click(); URL.revokeObjectURL(url);
};
const statusColor = s => ({complete:"#34d399",paid:"#34d399",invoiced:"#34d399",partial:"#fbbf24","in progress":"#fbbf24",received:"#a78bfa",ordered:"#525252",not_started:"#525252",unpaid:"#f87171",quoting:"#8b5cf6"}[s?.toLowerCase()]||"#525252");
const inputStyle = {width:"100%",padding:"11px 14px",background:"rgba(58,58,60,0.5)",border:"1px solid rgba(255,255,255,0.08)",borderRadius:10,color:"#d4d4d4",fontSize:13,outline:"none",fontFamily:"inherit"};

// --- SHARED COMPONENTS ---------------------------------------
const Card = ({children,style,onClick,hover}) => <div onClick={onClick} style={{background:"#111111",border:"1px solid #222222",borderRadius:12,padding:20,cursor:onClick?"pointer":"default",transition:"all 0.2s",...style}} onMouseEnter={e=>{if(hover||onClick){e.currentTarget.style.borderColor="#2dd4bf44";e.currentTarget.style.transform="translateY(-1px)"}}} onMouseLeave={e=>{if(hover||onClick){e.currentTarget.style.borderColor="rgba(255,255,255,0.04)";e.currentTarget.style.transform="translateY(0)"}}}>{children}</div>;
const Badge = ({label,color}) => <span style={{display:"inline-flex",padding:"3px 8px",borderRadius:4,fontSize:12,fontWeight:500,letterSpacing:0.5,textTransform:"uppercase",background:`${color}0d`,color:`${color}bb`}}>{label}</span>;
const StatCard = ({label,value,sub,icon,color="#2dd4bf"}) => <Card style={{display:"flex",flexDirection:"column",gap:10}}><span style={{fontSize:12,color:"#a3a3a3",fontWeight:500,textTransform:"uppercase",letterSpacing:1.5}}>{label}</span><div style={{fontSize:28,fontWeight:600,color:"#e5e5e5",fontFamily:"'JetBrains Mono',monospace",letterSpacing:-0.5}}>{value}</div>{sub&&<div style={{fontSize:12,color:"#8a8a8a"}}>{sub}</div>}</Card>;
const Header = ({title,sub,action}) => <div style={{display:"flex",justifyContent:"space-between",alignItems:"flex-end",marginBottom:20}}><div><h2 style={{fontSize:22,fontWeight:700,color:"#e5e5e5",marginBottom:4,letterSpacing:-0.5}}>{title}</h2>{sub&&<p style={{fontSize:13,color:"#a3a3a3"}}>{sub}</p>}</div>{action}</div>;
const Btn = ({children,onClick,v="primary",style:s}) => {const st={primary:{background:"#2dd4bf",color:"#000000",fontWeight:600},secondary:{background:"transparent",color:"#a3a3a3",border:"1px solid #222222"},ghost:{background:"transparent",color:"#2dd4bf",border:"1px solid rgba(45,212,191,0.15)"},danger:{background:"rgba(248,113,113,0.08)",color:"#f87171",border:"1px solid rgba(248,113,113,0.15)"}};return <button onClick={onClick} style={{padding:"8px 16px",borderRadius:8,border:"none",cursor:"pointer",fontSize:13,fontFamily:"inherit",display:"inline-flex",alignItems:"center",gap:6,transition:"all 0.2s",...st[v],...s}}>{children}</button>};
const Bar = ({value,max,color="#2dd4bf",height=6}) => <div style={{width:"100%",height,background:"rgba(255,255,255,0.04)",borderRadius:height,overflow:"hidden"}}><div style={{width:`${Math.min((value/(max||1))*100,100)}%`,height:"100%",background:color,borderRadius:height,transition:"width 0.6s cubic-bezier(0.25,0.1,0.25,1)"}}/></div>;

const Tbl = ({columns,data,onRowClick}) => <div style={{overflowX:"auto",borderRadius:10,border:"1px solid #222222"}}><table style={{width:"100%",borderCollapse:"collapse",fontSize:13}}><thead><tr style={{background:"#111111"}}>{columns.map((c,i)=><th key={i} style={{padding:"10px 14px",textAlign:"left",fontWeight:600,color:"#a3a3a3",fontSize:12,textTransform:"uppercase",letterSpacing:0.8,borderBottom:"1px solid #222222"}}>{c.header}</th>)}</tr></thead><tbody>{data.map((row,ri)=><tr key={row.id||ri} onClick={()=>onRowClick?.(row)} style={{cursor:onRowClick?"pointer":"default",transition:"background 0.15s",background:ri%2===1?"rgba(255,255,255,0.015)":"transparent"}} onMouseEnter={e=>{e.currentTarget.style.background=onRowClick?"#2dd4bf0a":"rgba(255,255,255,0.03)"}} onMouseLeave={e=>{e.currentTarget.style.background=ri%2===1?"rgba(255,255,255,0.015)":"transparent"}}>{columns.map((c,ci)=><td key={ci} style={{padding:"10px 14px",borderBottom:"1px solid rgba(255,255,255,0.02)",color:"#a3a3a3"}}>{c.render?c.render(row):row[c.key]}</td>)}</tr>)}</tbody></table></div>;

import { db } from './supabase';
import CsvUploadPage from './CsvUpload';

// --- PDF EXPORT: zero dependencies, works everywhere ---------
function usePrintOverlay() {
  const triggerPrint = (title, html) => {
    const w = window.open('', '_blank');
    if (!w) { alert('Please allow popups for PDF export'); return; }
    const fname = (title || 'document').replace(/[^a-zA-Z0-9-_ ]/g, '');
    w.document.write('<!DOCTYPE html><html><head><meta charset="utf-8"><title>' + title + '</title><style>' +
      'body{font-family:Satoshi,Arial,sans-serif;padding:40px;color:#111;max-width:760px;margin:0 auto}' +
      'h2{font-size:14px;color:#666;margin:16px 0 8px}' +
      'table{width:100%;border-collapse:collapse;margin:12px 0;font-size:12px}' +
      'th{background:#f5f5f4;padding:8px;text-align:left;border-bottom:2px solid #ddd;font-size:11px;text-transform:uppercase;color:#666}' +
      'td{padding:8px;border-bottom:1px solid #eee}' +
      '.total-row td{border-top:2px solid #2dd4bf;font-weight:bold;font-size:14px}' +
      '.hdr{display:flex;justify-content:space-between;margin-bottom:24px}' +
      '.hdr div{font-size:12px;color:#666}' +
      '.co{font-size:18px;font-weight:bold;color:#111}' +
      '.gold{color:#b8923c}' +
      '.dl-bar{position:fixed;top:0;left:0;right:0;background:#111;padding:10px 20px;display:flex;gap:10px;align-items:center;z-index:999;border-bottom:2px solid #2dd4bf}' +
      '.dl-bar button{padding:10px 24px;font-size:14px;font-weight:700;border:none;border-radius:6px;cursor:pointer}' +
      '@media print{.dl-bar{display:none!important}}' +
      '</style></head><body>' +
      '<div class="dl-bar">' +
      '<button id="dl-btn" style="background:#2dd4bf;color:#111">Download PDF</button>' +
      '<button onclick="window.close()" style="background:#333;color:#fff">Close</button>' +
      '<span style="color:#666;font-size:13px;margin-left:12px" id="dl-status">Preview - click Download PDF to save</span>' +
      '</div>' +
      '<div style="margin-top:56px">' + html + '</div>' +
      '<script src="https://cdnjs.cloudflare.com/ajax/libs/html2pdf.js/0.10.1/html2pdf.bundle.min.js"><\/script>' +
      '<script>' +
      'document.getElementById("dl-btn").onclick=function(){' +
        'var el=document.querySelector("[style*=margin-top]");' +
        'document.getElementById("dl-status").textContent="Generating PDF...";' +
        'document.getElementById("dl-btn").disabled=true;' +
        'html2pdf().set({' +
          'margin:[10,10,10,10],' +
          'filename:"' + fname + '.pdf",' +
          'image:{type:"jpeg",quality:0.98},' +
          'html2canvas:{scale:2,useCORS:true},' +
          'jsPDF:{unit:"mm",format:"letter",orientation:"portrait"},' +
          'pagebreak:{mode:["css","legacy"],before:".page-break-before"}' +
        '}).from(el).save().then(function(){' +
          'document.getElementById("dl-status").textContent="PDF downloaded!";' +
          'document.getElementById("dl-btn").disabled=false;' +
        '}).catch(function(){' +
          'document.getElementById("dl-status").textContent="Download failed - try Save As PDF from print";' +
          'document.getElementById("dl-btn").disabled=false;' +
          'window.print();' +
        '});' +
      '};' +
      '<\/script>' +
      '</body></html>');
    w.document.close();
    w.focus();
  };
  const PrintOverlay = () => null;
  return { triggerPrint, PrintOverlay };
}

